<?php
require_once __DIR__.'/functions.php';$member=require_member();
$stmt=db()->prepare('SELECT c.id,c.nombre,c.contenido,c.fecha,parent.contenido parent_content,p.titulo,p.slug FROM comments c JOIN comments parent ON parent.id=c.parent_id JOIN posts p ON p.id=c.post_id WHERE parent.member_id=? AND c.aprobado=0 ORDER BY c.fecha DESC');$stmt->execute([$member['id']]);$replies=$stmt->fetchAll();
render_header('Respuestas pendientes',['robots'=>'noindex,nofollow']);?><section class="panel"><div class="moderation-title"><div><h1>Respuestas pendientes</h1><p class="muted">Aprueba o elimina las respuestas directas a tus comentarios.</p></div><span class="count-badge"><?=count($replies)?></span></div><?php foreach($replies as $reply):?><article class="moderation"><small><a href="/<?=e($reply['slug'])?>"><?=e($reply['titulo'])?></a></small><p class="quoted-comment">“<?=e(mb_strimwidth($reply['parent_content'],0,140,'…'))?>”</p><strong><?=e($reply['nombre'])?></strong><p><?=nl2br(e($reply['contenido']))?></p><div class="actions"><form method="post" action="/comment-owner-action.php"><input type="hidden" name="csrf_token" value="<?=csrf_token()?>"><input type="hidden" name="comment_id" value="<?=(int)$reply['id']?>"><button class="button" name="action" value="approve">Aprobar</button><button class="button danger-bg" name="action" value="delete">Eliminar</button></form></div></article><?php endforeach;?><?php if(!$replies):?><p class="empty">No tienes respuestas pendientes.</p><?php endif;?></section><?php render_footer();
